#include <iostream>
#include <cmath>
#include <iomanip>

#ifndef M_PI
#define M_PI 3.14159265358979323846
#endif

class Circle {
private:
    double radius;

public:
    Circle() : radius(1.0) {}
    Circle(double r) : radius(r) {}
    double calculateArea() {
        return M_PI * radius * radius;
    }
    void printRadius() {
        std::cout << "Radius: " << radius << std::endl;
    }
};

int main() {
    Circle c1;
    std::cout << "Circle 1 (default):\n";
    c1.printRadius();
    std::cout << "Area: " << std::fixed << std::setprecision(4) << c1.calculateArea() << "\n";

    Circle c2(5.0);
    std::cout << "\nCircle 2 (radius 5.0):\n";
    c2.printRadius();
    std::cout << "Area: " << std::fixed << std::setprecision(4) << c2.calculateArea() << "\n";

    Circle c3(0.0);
    std::cout << "\nCircle 3 (radius 0.0):\n";
    c3.printRadius();
    std::cout << "Area: " << std::fixed << std::setprecision(4) << c3.calculateArea() << "\n";

    return 0;
}
